wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(110525745075295948107)
,p_plug_name=>'Bares visitados por ciudad y presupuesto del bar'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(110240282281271443175)
,p_plug_display_sequence=>80
,p_include_in_reg_disp_sel_yn=>'Y'
,p_plug_new_grid_row=>false
,p_plug_new_grid_column=>false
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    b.CIUDAD,',
'    COUNT(DISTINCT CASE WHEN b.PRESUPUESTO = ''Alto'' THEN b.ID END) as bares_alto,',
'    COUNT(DISTINCT CASE WHEN b.PRESUPUESTO = ''Medio'' THEN b.ID END) as bares_medio,',
'    COUNT(DISTINCT CASE WHEN b.PRESUPUESTO = ''Bajo'' THEN b.ID END) as bares_bajo,',
'    -- El total de bares visitados en la ciudad',
'    COUNT(DISTINCT b.ID) AS total_bares_visitados,',
'    ',
'    -- Coordenadas basadas en la ciudad del BAR',
'    CASE b.CIUDAD ',
'        WHEN ''Bogota'' THEN 4.7110 WHEN ''Medellin'' THEN 6.2442 WHEN ''Cali'' THEN 3.4516 ',
'        WHEN ''Villavicencio'' THEN 4.1420 WHEN ''Bucaramanga'' THEN 7.1193 WHEN ''Monteria'' THEN 8.7479 ',
'        WHEN ''Manizales'' THEN 5.0688 WHEN ''Santa Marta'' THEN 11.2407 WHEN ''Ibague'' THEN 4.4388 ',
'        WHEN ''Cartagena'' THEN 10.3910 WHEN ''Pereira'' THEN 4.8087 WHEN ''Cucuta'' THEN 7.8939 ',
'        WHEN ''Sincelejo'' THEN 9.3047 WHEN ''Armenia'' THEN 4.5338 WHEN ''BARESranquilla'' THEN 10.9685 ',
'        ELSE 4.5 ',
'    END AS latitud,',
'    CASE b.CIUDAD ',
'        WHEN ''Bogota'' THEN -74.0721 WHEN ''Medellin'' THEN -75.5812 WHEN ''Cali'' THEN -76.5320 ',
'        WHEN ''Villavicencio'' THEN -73.6266 WHEN ''Bucaramanga'' THEN -73.1227 WHEN ''Monteria'' THEN -75.8814 ',
'        WHEN ''Manizales'' THEN -75.5173 WHEN ''Santa Marta'' THEN -74.1990 WHEN ''Ibague'' THEN -75.2322 ',
'        WHEN ''Cartagena'' THEN -75.4794 WHEN ''Pereira'' THEN -75.6906 WHEN ''Cucuta'' THEN -72.5078 ',
'        WHEN ''Sincelejo'' THEN -75.3977 WHEN ''Armenia'' THEN -75.6811 WHEN ''BARESranquilla'' THEN -74.7813 ',
'        ELSE -74.2 ',
'    END AS longitud',
'FROM BARES b',
'JOIN FRECUENTAN f ON b.ID = f.ID_BAR',
'GROUP BY b.CIUDAD'))
,p_lazy_loading=>true
,p_plug_source_type=>'NATIVE_MAP_REGION'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
);
