wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(110556384413196647942)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Insertar detalles habitacion'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  DECLARE',
'    -- Cambiar :P_NOMBRE por :P8_NOMBRE para consistencia',
'    v_nombre VARCHAR2(100) := :P8_NOMBRE;',
unistr('    v_hotel  NUMBER        := :P8_ID_HOTELES;  -- tambi\00E9n unificar este'),
'  BEGIN',
'    INSERT INTO camas_por_habitacion',
'      (tipo_cama, nombre_tipo_habitacion, id_hoteles, cantidad)',
'    VALUES',
'      (:P_TIPOS_CAMA, :P8_NOMBRE, :P8_ID_HOTELES, :P_CANTIDAD_CAMAS);',
'',
'    FOR i IN (',
'      SELECT column_value AS val',
'      FROM TABLE(apex_string.split(:P_COMODIDADES, '':''))',
'      WHERE column_value IS NOT NULL',
'    ) LOOP',
'      INSERT INTO comodidades_por_tipo',
'        (nombre_comodidad, nombre_tipo_habitacion, id_hoteles)',
'      VALUES (i.val, v_nombre, v_hotel);',
'    END LOOP;',
'',
'    FOR i IN (',
'      SELECT column_value AS val',
'      FROM TABLE(apex_string.split(:P_SERVICIOS, '':''))',
'      WHERE column_value IS NOT NULL',
'    ) LOOP',
'      INSERT INTO servicios_por_tipo',
'        (nombre_servicio, nombre_tipo_habitacion, id_hoteles)',
'      VALUES (i.val, v_nombre, v_hotel);',
'    END LOOP;',
'  END;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(112062542355527910447)
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(110556385044731647948)
,p_process_sequence=>30
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Actualizar detalles habitacion'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  DELETE FROM comodidades_por_tipo',
'  WHERE nombre_tipo_habitacion = :P8_NOMBRE',
'  AND id_hoteles = :P8_ID_HOTELES;',
'',
'  DELETE FROM servicios_por_tipo',
'  WHERE nombre_tipo_habitacion = :P8_NOMBRE',
'  AND id_hoteles = :P8_ID_HOTELES;',
'',
'  DELETE FROM camas_por_habitacion',
'  WHERE nombre_tipo_habitacion = :P8_NOMBRE',
'  AND id_hoteles = :P8_ID_HOTELES;',
'',
'  INSERT INTO camas_por_habitacion',
'    (tipo_cama, nombre_tipo_habitacion, id_hoteles, cantidad)',
'  VALUES',
'    (:P8_TIPOs_CAMA, :P8_NOMBRE, :P8_ID_HOTELES, :P8_CANTIDAD_CAMAS);',
'',
'  FOR i IN (',
'    SELECT column_value as val',
'    FROM TABLE(apex_string.split(:P8_COMODIDADES, '':''))',
'    WHERE column_value IS NOT NULL',
'  ) LOOP',
'    INSERT INTO comodidades_por_tipo',
'      (nombre_comodidad, nombre_tipo_habitacion, id_hoteles)',
'    VALUES (i.val, :P8_NOMBRE, :P8_ID_HOTELES);',
'  END LOOP;',
'',
'  FOR i IN (',
'    SELECT column_value as val',
'    FROM TABLE(apex_string.split(:P8_SERVICIOS, '':''))',
'    WHERE column_value IS NOT NULL',
'  ) LOOP',
'    INSERT INTO servicios_por_tipo',
'      (nombre_servicio, nombre_tipo_habitacion, id_hoteles)',
'    VALUES (i.val, :P8_NOMBRE, :P8_ID_HOTELES);',
'  END LOOP;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(112062541965750910446)
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(112062543161296910447)
,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_region_id=>wwv_flow_imp.id(112062535855657910441)
,p_process_type=>'NATIVE_FORM_INIT'
,p_process_name=>'Initialize form Registrar habitaciones para hotel'
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(110556384986060647947)
,p_process_sequence=>30
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Precargar detalles'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  IF :P8_NOMBRE IS NOT NULL AND :P8_ID_HOTELES IS NOT NULL THEN',
'    ',
'    SELECT LISTAGG(nombre_comodidad, '':'') ',
'      WITHIN GROUP (ORDER BY nombre_comodidad)',
'    INTO :P8_COMODIDADES',
'    FROM comodidades_por_tipo',
'    WHERE nombre_tipo_habitacion = :P8_NOMBRE',
'    AND id_hoteles = :P8_ID_HOTELES;',
'',
'    SELECT cph.tipo_cama, cph.cantidad',
'    INTO :P8_TIPOS_CAMA, :P8_CANTIDAD_CAMAS',
'    FROM camas_por_habitacion cph',
'    JOIN camas c ON cph.tipo_cama = c.tipo',
'    WHERE cph.nombre_tipo_habitacion = :P8_NOMBRE',
'    AND cph.id_hoteles = :P8_ID_HOTELES',
'    AND ROWNUM = 1;',
'',
'    SELECT LISTAGG(nombre_servicio, '':'')',
'      WITHIN GROUP (ORDER BY nombre_servicio)',
'    INTO :P8_SERVICIOS',
'    FROM servicios_por_tipo',
'    WHERE nombre_tipo_habitacion = :P8_NOMBRE',
'    AND id_hoteles = :P8_ID_HOTELES;',
'',
'  END IF;',
'EXCEPTION',
'  WHEN NO_DATA_FOUND THEN NULL;',
'END;'))
,p_process_clob_language=>'PLSQL'
);
end;
/
