'  r.fecha_entrada,',
'  r.fecha_salida,',
'  r.num_adultos,',
'  r.num_ninos,',
'  r.precio_total,',
'  r.estado,',
'  r.id_hoteles,',
'  CASE ',
'    WHEN r.estado = ''completada'' ',
'    THEN ''<a href="f?p=&APP_ID.:21:&SESSION.::NO::P21_ID_RESERVA,P21_ID_HOTEL:'' || r.id || '','' || r.id_hoteles || ''" class="t-Button t-Button--small t-Button--hot">Resenar</a>''',
