 p_id=>wwv_flow_imp.id(112074298154763896462)
,p_plug_name=>'Editar habitacion'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(110240272475695443169)
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    t.nombre,',
'    t.id_hoteles,',
'    t.costo_base_alta,',
'    t.costo_base_baja,',
'    t.dimensiones,',
'    t.cap_maxima,',
'    t.tipo_vista,',
'    LISTAGG(DISTINCT c.tipo_cama || '' x'' || c.cantidad, '', '') ',
'        WITHIN GROUP (ORDER BY c.tipo_cama) AS camas,',
'    LISTAGG(DISTINCT cp.nombre_comodidad, '', '') ',
'        WITHIN GROUP (ORDER BY cp.nombre_comodidad) AS comodidades',
'FROM tipos_habitacion t',
'LEFT JOIN camas_por_habitacion c ',
'    ON c.nombre_tipo_habitacion = t.nombre ',
'    AND c.id_hoteles = t.id_hoteles',
'LEFT JOIN comodidades_por_tipo cp ',
'    ON cp.nombre_tipo_habitacion = t.nombre ',
'    AND cp.id_hoteles = t.id_hoteles',
'GROUP BY ',
'    t.nombre, t.id_hoteles, t.costo_base_alta, t.costo_base_baja,',
'    t.dimensiones, t.cap_maxima, t.tipo_vista'))
,p_plug_source_type=>'NATIVE_IR'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_page_header=>'Editar habitacion'
);
