wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(112085435570069704614)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Validar disponibilidad'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_reservas NUMBER;',
'  v_habitaciones NUMBER;',
'BEGIN',
'  SELECT COUNT(*) INTO v_reservas',
'  FROM reservas',
'  WHERE nombre_tipo_habitacion = :P12_NOMBRE_TIPO_HABITACION',
'  AND id_hoteles = :P12_ID_HOTELES',
'  AND estado != ''cancelada''',
'  AND NOT (:P12_FECHA_SALIDA <= fecha_entrada ',
'           OR :P12_FECHA_ENTRADA >= fecha_salida);',
'',
'  SELECT cap_maxima INTO v_habitaciones',
'  FROM tipos_habitacion',
'  WHERE nombre = :P12_NOMBRE_TIPO_HABITACION',
'  AND id_hoteles = :P12_ID_HOTELES;',
'',
'  IF v_reservas >= v_habitaciones THEN',
'    raise_application_error(-20001,',
'      ''No hay habitaciones disponibles para esas fechas'');',
'  END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(112077042724022145171)
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(112077043928964145172)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_region_id=>wwv_flow_imp.id(112077033064434145163)
,p_process_type=>'NATIVE_FORM_DML'
,p_process_name=>'Process form Crear reserva'
,p_attribute_01=>'REGION_SOURCE'
,p_attribute_05=>'Y'
,p_attribute_06=>'Y'
,p_attribute_08=>'Y'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(112085435618634704615)
,p_process_sequence=>30
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Calcular procio total'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_noches NUMBER;',
'  v_costo_noche NUMBER;',
'  v_precio_servicios NUMBER := 0;',
'  v_precio_servicio NUMBER;',
'BEGIN',
'  v_noches := :P12_FECHA_SALIDA - :P12_FECHA_ENTRADA;',
'',
'  IF EXTRACT(MONTH FROM TO_DATE(:P12_FECHA_ENTRADA, ''DD/MM/YYYY'')) ',
'     IN (6,7,8,12) THEN',
'    SELECT costo_base_alta INTO v_costo_noche',
'    FROM tipos_habitacion',
'    WHERE nombre = :P12_NOMBRE_TIPO_HABITACION',
'    AND id_hoteles = :P12_ID_HOTELES;',
'  ELSE',
'    SELECT costo_base_baja INTO v_costo_noche',
'    FROM tipos_habitacion',
'    WHERE nombre = :P12_NOMBRE_TIPO_HABITACION',
'    AND id_hoteles = :P12_ID_HOTELES;',
'  END IF;',
'',
'  FOR i IN (',
'    SELECT column_value as val',
'    FROM TABLE(apex_string.split(:P12_SERVICIOS_RESERVA, '':''))',
'    WHERE column_value IS NOT NULL',
'  ) LOOP',
'    SELECT precio INTO v_precio_servicio',
'    FROM servicios',
'    WHERE nombre = i.val;',
'    ',
'    v_precio_servicios := v_precio_servicios + v_precio_servicio;',
'  END LOOP;',
'',
'  :P12_PRECIO_TOTAL := (v_noches * v_costo_noche) + v_precio_servicios;',
'END;'))
