'BEGIN',
'  SELECT ',
'    u.nombre,',
'    u.apellido,',
'    u.telefono,',
'    u.email,',
'    u.contrasena,',
'    c.doc_identidad',
'  INTO ',
'    :P13_NOMBRE,',
'    :P13_APELLIDO,',
'    :P13_TELEFONO,',
'    :P13_EMAIL,',
'    :P13_CONTRASENA,',
'    :P13_DOC_IDENTIDAD',
'  FROM usuarios u',
'  JOIN clientes c ON u.id_usuario = c.id_usuario',
'  WHERE u.email = :APP_USER;',
'EXCEPTION',
'  WHEN NO_DATA_FOUND THEN NULL;',
