,p_name=>'Cancelar reserva'
,p_event_sequence=>10
,p_triggering_element_type=>'BUTTON'
,p_triggering_button_id=>wwv_flow_imp.id(112085435719222704616)
,p_bind_type=>'bind'
,p_execution_type=>'IMMEDIATE'
,p_bind_event_type=>'click'
);
wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(112085435982170704618)
,p_event_id=>wwv_flow_imp.id(112085435856226704617)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  IF TO_DATE(:P14_FECHA_ENTRADA, ''DD/MM/YYYY'') - SYSDATE >= 3 THEN',
'    UPDATE reservas ',
'    SET estado = ''cancelada''',
'    WHERE id = :P14_ID',
'    AND id_usuario_cliente = :APP_USER_ID;',
'  ELSE',
'    raise_application_error(-20002,',
unistr('      ''No se puede cancelar con menos de 3 d\00EDas de anticipaci\00F3n'');'),
'  END IF;',
'END;'))
,p_attribute_02=>'P14_FECHA_ENTRADA,P14_ID'
,p_attribute_05=>'PLSQL'
,p_wait_for_result=>'Y'
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(112091665581920140946)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_region_id=>wwv_flow_imp.id(112091655617714140937)
,p_process_type=>'NATIVE_FORM_DML'
,p_process_name=>'Process form Gestionar reservas'
,p_attribute_01=>'REGION_SOURCE'
,p_attribute_05=>'Y'
,p_attribute_06=>'Y'
,p_attribute_08=>'Y'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(112085436011062704619)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Modificar fechas reserva'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_reservas NUMBER;',
'  v_habitaciones NUMBER;',
'BEGIN',
'  SELECT COUNT(*) INTO v_reservas',
'  FROM reservas',
'  WHERE nombre_tipo_habitacion = :P14_NOMBRE_TIPO_HABITACION',
'  AND id_hoteles = :P14_ID_HOTELES',
'  AND estado != ''cancelada''',
'  AND id != :P14_ID',
'  AND NOT (:P14_FECHA_SALIDA <= fecha_entrada ',
'           OR :P14_FECHA_ENTRADA >= fecha_salida);',
'',
'  SELECT cap_maxima INTO v_habitaciones',
'  FROM tipos_habitacion',
'  WHERE nombre = :P14_NOMBRE_TIPO_HABITACION',
'  AND id_hoteles = :P14_ID_HOTELES;',
'',
'  IF v_reservas >= v_habitaciones THEN',
'    raise_application_error(-20001,',
'      ''No hay disponibilidad para esas fechas'');',
'  END IF;',
'',
'  UPDATE reservas SET',
'    fecha_entrada = TO_DATE(:P14_FECHA_ENTRADA, ''DD/MM/YYYY''),',
'    fecha_salida = TO_DATE(:P14_FECHA_SALIDA, ''DD/MM/YYYY'')',
'  WHERE id = :P14_ID',
'  AND id_usuario_cliente = :APP_USER_ID;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(112091663988188140944)
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(112091665168752140945)
,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_region_id=>wwv_flow_imp.id(112091655617714140937)
,p_process_type=>'NATIVE_FORM_INIT'
,p_process_name=>'Initialize form Gestionar reservas'
);
end;
