 p_id=>wwv_flow_imp.id(112231072807205762713)
,p_plug_name=>'Habitaciones Disponibles'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(110240272475695443169)
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT Habitaciones.numero AS numero_habitacion,',
'       Tipos_habitacion.nombre AS tipo_habitacion,',
'       Tipos_habitacion.id_hoteles,',
'       Tipos_habitacion.tipo_vista, Tipos_habitacion.dimensiones,',
'       Tipos_habitacion.cap_maxima,',
'       Tipos_habitacion.costo_base_alta, Tipos_habitacion.costo_base_baja',
'FROM   Habitaciones',
'INNER JOIN Tipos_habitacion ON  Tipos_habitacion.nombre     = Habitaciones.nombre_tipo_habitacion',
'                            AND Tipos_habitacion.id_hoteles = Habitaciones.id_hoteles',
'WHERE  Habitaciones.estado_mantenimiento = ''disponible''',
'AND    NOT EXISTS (SELECT 1',
'                   FROM   Reservas',
'                   WHERE  Reservas.nombre_tipo_habitacion = Habitaciones.nombre_tipo_habitacion',
'                   AND    Reservas.id_hoteles             = Habitaciones.id_hoteles',
'                   AND    Reservas.estado                 IN (''activa'',''pendiente'',''completada'')',
'                   AND    Reservas.fecha_entrada          < TO_DATE(:P16_FECHA_SALIDA,  ''MM/DD/YYYY'')',
'                   AND    Reservas.fecha_salida           > TO_DATE(:P16_FECHA_ENTRADA, ''MM/DD/YYYY''))',
'AND    (:P16_ID_HOTEL IS NULL OR Habitaciones.id_hoteles  = :P16_ID_HOTEL)',
'ORDER BY Tipos_habitacion.costo_base_baja ASC,',
'         Tipos_habitacion.nombre          ASC;'))
,p_plug_source_type=>'NATIVE_IR'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_page_header=>'Habitaciones Disponibles'
);
