wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(112238587928359111690)
,p_plug_name=>'Evolucion de Reservas'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(110240272475695443169)
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT Hoteles.id,',
'       Hoteles.nombre                              AS hotel,',
'       Ciudades.nombre                             AS ciudad,',
'       EXTRACT(YEAR  FROM Reservas.fecha_entrada)  AS anio,',
'       EXTRACT(MONTH FROM Reservas.fecha_entrada)  AS mes,',
'       Reservas.estado,',
'       COUNT(Reservas.id)                          AS total_reservas',
'FROM   Reservas',
'INNER JOIN   Hoteles  ON Hoteles.id  = Reservas.id_hoteles',
'INNER JOIN   Ciudades ON Ciudades.id = Hoteles.id_ciudades',
'WHERE  Reservas.fecha_entrada >= TO_DATE(:P17_FECHA_INICIO, ''MM/DD/YYYY'')',
'AND    Reservas.fecha_salida  <= TO_DATE(:P17_FECHA_FIN,    ''MM/DD/YYYY'')',
'AND    (:P17_ID_HOTEL  IS NULL OR Hoteles.id          = :P17_ID_HOTEL)',
'AND    (:P17_ID_CIUDAD IS NULL OR Hoteles.id_ciudades = :P17_ID_CIUDAD)',
'GROUP BY Hoteles.id,',
'         Hoteles.nombre,',
'         Ciudades.nombre,',
'         EXTRACT(YEAR  FROM Reservas.fecha_entrada),',
'         EXTRACT(MONTH FROM Reservas.fecha_entrada),',
'         Reservas.estado',
'ORDER BY ciudad,',
'         hotel,',
'         anio,',
'         mes;'))
,p_plug_source_type=>'NATIVE_IR'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_page_header=>'Evolucion de Reservas'
);
