wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(112241203262188179145)
,p_plug_name=>'Huespedes por Ciudad'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(110240272475695443169)
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT Ciudades.id                                           AS id_ciudad,',
'       Ciudades.nombre                                       AS ciudad,',
'       Hoteles.id                                            AS id_hotel,',
'       Hoteles.nombre                                        AS hotel,',
'       COUNT(Reservas.id)                                    AS total_reservas,',
'       SUM(Reservas.num_adultos + Reservas.num_ninos)        AS total_huespedes,',
'       AVG(Reservas.num_adultos + Reservas.num_ninos)        AS promedio_huespedes',
'FROM   Reservas',
'INNER JOIN   Hoteles  ON Hoteles.id  = Reservas.id_hoteles',
'INNER JOIN   Ciudades ON Ciudades.id = Hoteles.id_ciudades',
'WHERE  Reservas.fecha_entrada <= TO_DATE(:P18_FECHA_FIN,    ''MM/DD/YYYY'')',
'AND    Reservas.fecha_salida  >= TO_DATE(:P18_FECHA_INICIO, ''MM/DD/YYYY'')',
'AND    Reservas.estado        IN (''activa'',''completada'')',
'AND    (:P18_ID_CIUDAD IS NULL OR Hoteles.id_ciudades = :P18_ID_CIUDAD)',
'AND    (:P18_ID_HOTEL  IS NULL OR Hoteles.id          = :P18_ID_HOTEL)',
'GROUP BY Ciudades.id,',
'         Ciudades.nombre,',
'         Hoteles.id,',
'         Hoteles.nombre',
'ORDER BY Ciudades.nombre,',
'         total_huespedes DESC;'))
,p_plug_source_type=>'NATIVE_IR'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_page_header=>'Huespedes por Ciudad'
);
