,p_plug_name=>'Ingresos por Hotel'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(110240272475695443169)
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT Ciudades.id                    AS id_ciudad,',
'       Ciudades.nombre                AS ciudad,',
'       Hoteles.id                     AS id_hotel,',
'       Hoteles.nombre                 AS hotel,',
'       COUNT(Reservas.id)             AS total_reservas,',
'       SUM(Reservas.precio_total)     AS ingresos_total,',
'       AVG(Reservas.precio_total)     AS ingreso_promedio,',
'       MAX(Reservas.precio_total)     AS reserva_mas_alta,',
'       MIN(Reservas.precio_total)     AS reserva_mas_baja',
'FROM   Reservas',
'INNER JOIN   Hoteles  ON Hoteles.id  = Reservas.id_hoteles',
'INNER JOIN   Ciudades ON Ciudades.id = Hoteles.id_ciudades',
'WHERE  EXTRACT(YEAR FROM Reservas.fecha_entrada) = :P19_ANIO',
'AND    Reservas.estado                           IN (''activa'',''completada'')',
'AND    (:P19_ID_CIUDAD IS NULL OR Hoteles.id_ciudades = :P19_ID_CIUDAD)',
'AND    (:P19_ID_HOTEL  IS NULL OR Hoteles.id          = :P19_ID_HOTEL)',
'GROUP BY Ciudades.id,',
'         Ciudades.nombre,',
'         Hoteles.id,',
'         Hoteles.nombre',
'ORDER BY Ciudades.nombre,',
'         ingresos_total DESC;'))
,p_plug_source_type=>'NATIVE_IR'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_page_header=>'Ingresos por Hotel'
);
