,p_plug_name=>'Breadcrumb'
,p_region_template_options=>'#DEFAULT#:t-BreadcrumbRegion--useBreadcrumbTitle'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(110240294659941443183)
,p_plug_display_sequence=>10
,p_plug_display_point=>'REGION_POSITION_01'
,p_menu_id=>wwv_flow_imp.id(110240179481915443107)
,p_plug_source_type=>'NATIVE_BREADCRUMB'
,p_menu_template_id=>wwv_flow_imp.id(110240356763168443225)
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(112242478813554256557)
,p_plug_name=>'Servicios y Tipos Populares'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_imp.id(110240272475695443169)
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ''TIPO_HABITACION''                              AS categoria,',
'       Hoteles.id                                     AS id_hotel,',
'       Hoteles.nombre                                 AS hotel,',
'       Ciudades.nombre                                AS ciudad,',
'       Reservas.nombre_tipo_habitacion                AS nombre,',
'       COUNT(Reservas.id)                             AS total_reservas,',
'       SUM(Reservas.num_adultos + Reservas.num_ninos) AS total_huespedes',
'FROM   Reservas',
'INNER JOIN   Hoteles  ON Hoteles.id  = Reservas.id_hoteles',
'INNER JOIN   Ciudades ON Ciudades.id = Hoteles.id_ciudades',
'WHERE  Reservas.fecha_entrada >= TO_DATE(:P20_FECHA_INICIO, ''MM/DD/YYYY'')',
'AND    Reservas.fecha_salida  <= TO_DATE(:P20_FECHA_FINAL,  ''MM/DD/YYYY'')',
'AND    Reservas.estado        IN (''activa'',''completada'')',
'AND    (:P20_ID_HOTEL IS NULL OR Hoteles.id = :P20_ID_HOTEL)',
'GROUP BY Hoteles.id,',
'         Hoteles.nombre,',
'         Ciudades.nombre,',
'         Reservas.nombre_tipo_habitacion',
'',
'UNION ALL',
'',
'SELECT ''SERVICIO''                                     AS categoria,',
'       Hoteles.id                                     AS id_hotel,',
'       Hoteles.nombre                                 AS hotel,',
'       Ciudades.nombre                                AS ciudad,',
'       Servicios_por_tipo.nombre_servicio             AS nombre,',
'       COUNT(Reservas.id)                             AS total_reservas,',
'       NULL                                           AS total_huespedes',
'FROM   Reservas',
'INNER JOIN   Hoteles            ON Hoteles.id                                = Reservas.id_hoteles',
'INNER JOIN   Ciudades           ON Ciudades.id                               = Hoteles.id_ciudades',
'INNER JOIN   Servicios_por_tipo ON Servicios_por_tipo.nombre_tipo_habitacion = Reservas.nombre_tipo_habitacion',
'                          AND Servicios_por_tipo.id_hoteles            = Reservas.id_hoteles',
'WHERE  Reservas.fecha_entrada >= TO_DATE(:P20_FECHA_INICIO, ''MM/DD/YYYY'')',
'AND    Reservas.fecha_salida  <= TO_DATE(:P20_FECHA_FINAL,  ''MM/DD/YYYY'')',
'AND    Reservas.estado        IN (''activa'',''completada'')',
'AND    (:P20_ID_HOTEL IS NULL OR Hoteles.id = :P20_ID_HOTEL)',
'GROUP BY Hoteles.id,',
'         Hoteles.nombre,',
'         Ciudades.nombre,',
'         Servicios_por_tipo.nombre_servicio',
'ORDER BY ciudad,',
'         hotel,',
'         categoria,',
'         total_reservas DESC;'))
,p_plug_source_type=>'NATIVE_IR'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_page_header=>'Servicios y Tipos Populares'
);
