,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_name=>unistr('Llamar API Crear Rese\00F1a')
,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var apiUrl = ''https://entrega-nosql.onrender.com'';',
'',
'var idReserva = apex.item(''P21_ID_RESERVA'').getValue();',
'var idHotel   = apex.item(''P21_ID_HOTEL'').getValue();',
'var idCliente = apex.item(''P21_ID_CLIENTE'').getValue();',
'var califica  = apex.item(''P21_CALIFICACION'').getValue();',
'var texto     = apex.item(''P21_TEXTO'').getValue();',
'',
'if (!califica || !texto.trim()) {',
'  apex.message.showErrors([{',
'    type: ''error'',',
'    location: ''page'',',
unistr('    message: ''Debes ingresar una calificaci\00F3n y un texto.'''),
'  }]);',
'  return;',
'}',
'',
'fetch(apiUrl + ''/resenas'', {',
'  method: ''POST'',',
'  headers: { ''Content-Type'': ''application/json'' },',
'  body: JSON.stringify({',
'    id_reserva:   parseInt(idReserva),',
'    id_hotel:     parseInt(idHotel),',
'    id_cliente:   parseInt(idCliente),',
'    calificacion: parseInt(califica),',
'    texto:        texto.trim()',
'  })',
'})',
'.then(function(r) { return r.json(); })',
'.then(function(data) {',
'  if (data.id) {',
unistr('    apex.message.showPageSuccess(''\00A1Rese\00F1a publicada exitosamente!'');'),
'  } else {',
'    apex.message.showErrors([{',
'      type: ''error'',',
'      location: ''page'',',
unistr('      message: data.detail || ''Error al publicar la rese\00F1a.'''),
'    }]);',
'  }',
'})',
'.catch(function() {',
'  apex.message.showErrors([{',
'    type: ''error'',',
'    location: ''page'',',
'    message: ''No se pudo conectar con el servidor.''',
'  }]);',
'});'))
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(115475606190351971507)
,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Cargar ID Cliente'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  SELECT C.ID_USUARIO',
'  INTO   :P21_ID_CLIENTE',
'  FROM   USUARIOS_APP UA',
'  JOIN   CLIENTES C ON C.ID_USUARIO = UA.ID',
'  WHERE  UPPER(UA.USUARIO) = UPPER(:APP_USER);',
'EXCEPTION',
'  WHEN NO_DATA_FOUND THEN',
'    :P21_ID_CLIENTE := NULL;',
'END;'))
,p_process_clob_language=>'PLSQL'
);
end;
