begin
wwv_flow_imp_page.create_page(
 p_id=>24
,p_name=>unistr('Rese\00F1as del Hotel')
,p_alias=>unistr('RESE\00D1AS-DEL-HOTEL')
,p_step_title=>unistr('Rese\00F1as del Hotel')
,p_autocomplete_on_off=>'OFF'
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var apiUrl = ''https://entrega-nosql.onrender.com'';',
'',
'function cargarHoteles() {',
'  apex.server.process(''GET_HOTELES'', {}, {',
'    success: function(data) {',
'      var select = document.getElementById(''hotel-select'');',
'      if (!select) return;',
'      data.hoteles.forEach(function(h) {',
'        var opt = document.createElement(''option'');',
'        opt.value = h.id;',
'        opt.text  = h.nombre;',
'        select.appendChild(opt);',
'      });',
'      cargarResenas();',
'    }',
'  });',
'}',
'',
'function cargarResenas() {',
'  var idHotel = document.getElementById(''hotel-select'') ',
'                ? document.getElementById(''hotel-select'').value ',
'                : apex.item(''P24_ID_HOTEL'').getValue() || 2;',
'  var orden   = apex.item(''P24_ORDEN'').getValue() || ''fecha'';',
'',
'  fetch(apiUrl + ''/hoteles/'' + idHotel + ''/resenas?orden='' + orden + ''&page=1&page_size=10'')',
'  .then(function(r) { return r.json(); })',
'  .then(function(data) {',
'    var html = '''';',
'',
'    if (data.destacada) {',
'      var d = data.destacada;',
'      html += ''<div style="background:#fff8e1;border-left:4px solid #ffc107;padding:16px;margin-bottom:16px;border-radius:4px">'';',
'      html += ''<strong>Resena Destacada</strong><br>'';',
'      html += ''<span>'' + d.texto + ''</span><br>'';',
'      html += ''<small>Calificacion: '' + d.calificacion + ''/5 | '' + d.votos_util.count + '' util</small>'';',
'      html += ''</div>'';',
'    }',
'',
'    data.resenas.forEach(function(r) {',
'      html += ''<div style="border:1px solid #ddd;padding:16px;margin-bottom:12px;border-radius:4px;background:#fff">'';',
'      html += ''<strong>Calificacion: '' + r.calificacion + ''/5</strong>'';',
'      html += ''<span style="float:right;color:#888">'' + new Date(r.fecha_creacion).toLocaleDateString() + ''</span><br>'';',
'      html += ''<p>'' + r.texto + ''</p>'';',
'      html += ''<small>'' + r.votos_util.count + '' personas lo encontraron util</small>'';',
'      html += '' <button onclick="votarUtil(\'''' + r._id + ''\'')" style="margin-left:8px;padding:4px 10px;background:#1976d2;color:#fff;border:none;border-radius:4px;cursor:pointer">Util</button>'';',
'      if (r.respuesta_admin) {',
'        html += ''<div style="margin-top:8px;padding:8px;background:#f5f5f5;border-left:3px solid #1976d2">'';',
'        html += ''<strong>Respuesta del hotel:</strong> '' + r.respuesta_admin.texto;',
'        html += ''</div>'';',
'      }',
'      html += ''</div>'';',
'    });',
'',
'    if (data.resenas.length === 0 && !data.destacada) {',
'      html = ''<p>No hay resenas para este hotel aun.</p>'';',
'    }',
'',
'    document.getElementById(''resenas-container'').innerHTML = html;',
'  })',
'  .catch(function() {',
'    document.getElementById(''resenas-container'').innerHTML = ''<p>Error al cargar las resenas.</p>'';',
'  });',
'}',
'',
'function votarUtil(resenaId) {',
'  var idCliente = apex.item(''P24_ID_CLIENTE'').getValue() || 3;',
'',
'  fetch(apiUrl + ''/resenas/'' + resenaId + ''/votos'', {',
'    method: ''POST'',',
'    headers: { ''Content-Type'': ''application/json'' },',
'    body: JSON.stringify({ id_usuario: parseInt(idCliente) })',
'  })',
'  .then(function(r) { return r.json(); })',
'  .then(function(data) {',
'    if (data.mensaje) {',
'      apex.message.showPageSuccess(''Voto registrado!'');',
'      cargarResenas();',
'    } else {',
'      apex.message.showErrors([{ type: ''error'', location: ''page'', message: data.detail || ''Error al votar.'' }]);',
'    }',
'  })',
'  .catch(function() {',
'    apex.message.showErrors([{ type: ''error'', location: ''page'', message: ''Error de conexion.'' }]);',
'  });',
'}'))
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'cargarHoteles();',
'',
'apex.jQuery(''#P24_ORDEN'').change(function() {',
'  cargarResenas();',
'});'))
,p_page_template_options=>'#DEFAULT#'
,p_page_is_public_y_n=>'Y'
,p_protection_level=>'C'
,p_page_component_map=>'17'
,p_last_updated_by=>'ANDRES.RAMIREZ18'
