 p_id=>wwv_flow_imp.id(115497847452063843614)
,p_process_sequence=>10
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'GET_HOTELES'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_cursor SYS_REFCURSOR;',
'BEGIN',
'  apex_json.open_object;',
'  apex_json.open_array(''hoteles'');',
'  FOR r IN (SELECT ID, NOMBRE FROM HOTELES ORDER BY NOMBRE) LOOP',
'    apex_json.open_object;',
'    apex_json.write(''id'', r.ID);',
'    apex_json.write(''nombre'', r.NOMBRE);',
'    apex_json.close_object;',
'  END LOOP;',
'  apex_json.close_array;',
'  apex_json.close_object;',
'END;'))
,p_process_clob_language=>'PLSQL'
);
end;
