'var apiUrl = ''https://entrega-nosql.onrender.com'';',
'',
'function eliminarResena(resenaId) {',
'  apex.message.confirm(''Deseas eliminar esta resena?'', function(ok) {',
'    if (ok) {',
'      fetch(apiUrl + ''/resenas/'' + resenaId, { method: ''DELETE'' })',
'      .then(function(r) { return r.json(); })',
'      .then(function() {',
'        apex.message.showPageSuccess(''Resena eliminada.'');',
'        cargarHistorial();',
'      });',
'    }',
'  });',
'}',
'',
'function cargarHistorial() {',
'  var idCliente = apex.item(''P25_ID_CLIENTE'').getValue();',
'  var orden     = apex.item(''P25_ORDEN'').getValue() || ''fecha'';',
'',
'  fetch(apiUrl + ''/clientes/'' + idCliente + ''/resenas?orden='' + orden)',
'  .then(function(r) { return r.json(); })',
'  .then(function(resenas) {',
'    var html = ''<table style="width:100%;border-collapse:collapse">'';',
'    html += ''<thead style="background:#f5f5f5"><tr>'';',
'    html += ''<th style="padding:10px;text-align:left">Hotel</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Calificacion</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Texto</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Estado</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Votos</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Respuesta</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Fecha</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Acciones</th>'';',
'    html += ''</tr></thead><tbody>'';',
'',
'    resenas.forEach(function(r) {',
'      html += ''<tr style="border-bottom:1px solid #ddd">'';',
'      html += ''<td style="padding:10px">'' + r.id_hotel + ''</td>'';',
'      html += ''<td style="padding:10px">'' + r.calificacion + ''/5</td>'';',
'      html += ''<td style="padding:10px">'' + r.texto.substring(0, 60) + ''...</td>'';',
'      html += ''<td style="padding:10px">'' + r.estado + ''</td>'';',
'      html += ''<td style="padding:10px">'' + r.votos_util.count + ''</td>'';',
'      html += ''<td style="padding:10px">'' + (r.respuesta_admin ? ''Si'' : ''No'') + ''</td>'';',
'      html += ''<td style="padding:10px">'' + new Date(r.fecha_creacion).toLocaleDateString() + ''</td>'';',
'      if (r.estado === ''publicada'') {',
'        html += ''<td style="padding:10px">'';',
'        html += ''<a href="f?p=&APP_ID.:22:&SESSION.::NO:22:P22_RESENA_ID:'' + r._id + ''" style="margin-right:8px;padding:4px 10px;background:#1976d2;color:#fff;border-radius:4px;text-decoration:none">Editar</a>'';',
'        html += ''<button onclick="eliminarResena(\'''' + r._id + ''\'')" style="padding:4px 10px;background:#d32f2f;color:#fff;border:none;border-radius:4px;cursor:pointer">Eliminar</button>'';',
'        html += ''</td>'';',
'      } else {',
'        html += ''<td style="padding:10px">-</td>'';',
'      }',
'      html += ''</tr>'';',
'    });',
'',
'    html += ''</tbody></table>'';',
'',
'    if (resenas.length === 0) {',
'      html = ''<p>No tienes resenas aun.</p>'';',
'    }',
'',
'    document.getElementById(''historial-container'').innerHTML = html;',
'  })',
'  .catch(function() {',
'    document.getElementById(''historial-container'').innerHTML = ''<p>Error al cargar el historial.</p>'';',
'  });',
'}'))
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'cargarHistorial();',
'',
'apex.jQuery(''#P25_ORDEN'').change(function() {',
