,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var apiUrl = ''https://entrega-nosql.onrender.com'';',
'var resenaId = apex.item(''P26_RESENA_ID'').getValue();',
'var idAdmin  = apex.item(''P26_ID_ADMIN'').getValue();',
'var texto    = apex.item(''P26_TEXTO_RESPUESTA'').getValue();',
'',
'if (!texto.trim()) {',
'  apex.message.showErrors([{',
'    type: ''error'',',
'    location: ''page'',',
'    message: ''Debes escribir una respuesta.''',
'  }]);',
'  return;',
'}',
'',
'fetch(apiUrl + ''/resenas/'' + resenaId + ''/respuesta'', {',
'  method: ''PUT'',',
'  headers: { ''Content-Type'': ''application/json'' },',
'  body: JSON.stringify({',
'    id_admin: parseInt(idAdmin),',
'    texto:    texto.trim()',
'  })',
'})',
'.then(function(r) { return r.json(); })',
'.then(function(data) {',
'  if (data.mensaje) {',
'    apex.message.showPageSuccess(''Respuesta publicada exitosamente!'');',
'  } else {',
'    apex.message.showErrors([{',
'      type: ''error'',',
'      location: ''page'',',
'      message: data.detail || ''Error al publicar la respuesta.''',
'    }]);',
'  }',
'})',
'.catch(function() {',
'  apex.message.showErrors([{',
'    type: ''error'',',
'    location: ''page'',',
'    message: ''Error de conexion con el servidor.''',
'  }]);',
'});'))
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(115475610455882971550)
,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Cargar ID Admin'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'  SELECT A.ID_USUARIO',
'  INTO   :P26_ID_ADMIN',
'  FROM   USUARIOS_APP UA',
'  JOIN   ADMINISTRADORES A ON A.ID_USUARIO = UA.ID',
'  WHERE  UPPER(UA.USUARIO) = UPPER(:APP_USER);',
'EXCEPTION',
'  WHEN NO_DATA_FOUND THEN',
'    :P26_ID_ADMIN := NULL;',
'END;'))
,p_process_clob_language=>'PLSQL'
);
end;
