'  var desde = apex.item(''P29_FECHA_INICIO'').getValue();',
'  var hasta = apex.item(''P29_FECHA_FIN'').getValue();',
'',
'  if (!desde || !hasta) {',
'    apex.message.showErrors([{type: "error", message: "Ingrese fecha inicio y fecha fin."}]);',
'    return;',
'  }',
'',
'  fetch(apiUrl + ''/analytics/top-hoteles?desde='' + desde + ''&hasta='' + hasta)',
'  .then(function(r) { return r.json(); })',
'  .then(function(data) {',
'    var html = ''<table style="width:100%;border-collapse:collapse">'';',
'    html += ''<thead style="background:#f5f5f5"><tr>'';',
'    html += ''<th style="padding:10px;text-align:left">Hotel ID</th>'';',
unistr('    html += ''<th style="padding:10px;text-align:left">Calificaci\00F3n Promedio</th>'';'),
unistr('    html += ''<th style="padding:10px;text-align:left">Total Rese\00F1as</th>'';'),
'    html += ''</tr></thead><tbody>'';',
'    data.forEach(function(h) {',
'      html += ''<tr style="border-bottom:1px solid #ddd">'';',
'      html += ''<td style="padding:10px">'' + h.id_hotel + ''</td>'';',
'      html += ''<td style="padding:10px">'' + h.calificacion_promedio + ''</td>'';',
'      html += ''<td style="padding:10px">'' + h.total_resenas + ''</td>'';',
'      html += ''</tr>'';',
'    });',
'    html += ''</tbody></table>'';',
'    if (data.length === 0) html = ''<p>No hay resultados.</p>'';',
'    document.getElementById(''rfc1-container'').innerHTML = html;',
'  })',
'  .catch(function() {',
'    document.getElementById(''rfc1-container'').innerHTML = ''<p>Error al consultar.</p>'';',
'  });',
'}'))
