,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var ciudad = apex.item(''P29_CIUDAD'').getValue();',
'',
'if (!ciudad) {',
'  apex.message.showErrors([{type: "error", message: "Seleccione una ciudad."}]);',
'  return;',
'}',
'',
'apex.server.process(''OBTENER_HOTELES_CIUDAD'', {',
'  x01: ciudad',
'}, {',
'  dataType: ''text'',',
'  success: function(ids) {',
'    ids = ids.trim();',
'    if (!ids) {',
'      document.getElementById(''rfc3-container'').innerHTML = ''<p>No hay hoteles para esta ciudad.</p>'';',
'      return;',
'    }',
'    fetch(''https://entrega-nosql.onrender.com/analytics/comparativa-hoteles?hoteles='' + ids)',
'    .then(function(r) { return r.json(); })',
'    .then(function(data) {',
'      var html = ''<table style="width:100%;border-collapse:collapse">'';',
'      html += ''<thead style="background:#f5f5f5"><tr>'';',
