'  }',
'});'))
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(115509903328844563405)
,p_process_sequence=>10
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'obtener_nom_hoteles'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_json  VARCHAR2(32767) := ''{'';',
'  v_sep   VARCHAR2(1) := '''';',
'BEGIN',
'  FOR r IN (SELECT id, nombre FROM hoteles) LOOP',
'    v_json := v_json || v_sep || ''"'' || r.id || ''":"'' || r.nombre || ''"'';',
'    v_sep := '','';',
'  END LOOP;',
'  v_json := v_json || ''}'';',
'  HTP.prn(v_json);',
'END;'))
,p_process_clob_language=>'PLSQL'
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(115509904506148563417)
,p_process_sequence=>20
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'OBTENER_HOTELES_CIUDAD'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_ciudad VARCHAR2(200) := apex_application.g_x01;',
'  v_ids    VARCHAR2(4000) := '''';',
'  v_sep    VARCHAR2(1) := '''';',
'BEGIN',
'  FOR r IN (',
'    SELECT h.id',
'    FROM hoteles h',
'    JOIN ciudades c ON h.id_ciudades = c.id',
'    WHERE c.nombre = v_ciudad',
'  ) LOOP',
'    v_ids := v_ids || v_sep || r.id;',
'    v_sep := '','';',
'  END LOOP;',
'  HTP.prn(v_ids);',
'END;'))
,p_process_clob_language=>'PLSQL'
);
end;
