prompt --application/pages/page_00030
begin
wwv_flow_imp_page.create_page(
 p_id=>30
,p_name=>unistr('Panel Admin Rese\00F1as')
,p_alias=>unistr('PANEL-ADMIN-RESE\00D1AS')
,p_step_title=>unistr('Panel Admin Rese\00D1as')
,p_autocomplete_on_off=>'OFF'
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var apiUrl = ''https://entrega-nosql.onrender.com'';',
'',
'function cargarResenasAdmin() {',
'  var idHotel = apex.item(''P30_ID_HOTEL'').getValue();',
'  if (!idHotel) {',
'    document.getElementById(''admin-resenas-container'').innerHTML = ''<p>Selecciona un hotel.</p>'';',
'    return;',
'  }',
'',
'  fetch(apiUrl + ''/hoteles/'' + idHotel + ''/resenas?page=1&page_size=50'')',
'  .then(function(r) { return r.json(); })',
'  .then(function(data) {',
'    var html = ''<table style="width:100%;border-collapse:collapse">'';',
'    html += ''<thead style="background:#f5f5f5"><tr>'';',
'    html += ''<th style="padding:10px;text-align:left">ID</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Calificacion</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Texto</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Votos</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Destacada</th>'';',
'    html += ''<th style="padding:10px;text-align:left">Acciones</th>'';',
'    html += ''</tr></thead><tbody>'';',
'',
'    var todasResenas = [];',
'    if (data.destacada) todasResenas.push(data.destacada);',
'    todasResenas = todasResenas.concat(data.resenas);',
'',
'    todasResenas.forEach(function(r) {',
'      html += ''<tr style="border-bottom:1px solid #ddd">'';',
'      html += ''<td style="padding:10px">'' + r._id.substring(0,8) + ''...</td>'';',
'      html += ''<td style="padding:10px">'' + r.calificacion + ''/5</td>'';',
'      html += ''<td style="padding:10px">'' + r.texto.substring(0,50) + ''...</td>'';',
'      html += ''<td style="padding:10px">'' + r.votos_util.count + ''</td>'';',
'      html += ''<td style="padding:10px">'' + (r.destacada ? ''Si'' : ''No'') + ''</td>'';',
'      html += ''<td style="padding:10px">'';',
'      html += ''<a href="f?p=&APP_ID.:26:&SESSION.::NO:26:P26_RESENA_ID:'' + r._id + ''" style="margin-right:4px;padding:4px 8px;background:#1976d2;color:#fff;border-radius:4px;text-decoration:none;font-size:12px">Responder</a>'';',
'      html += ''<a href="f?p=&APP_ID.:27:&SESSION.::NO:27:P27_RESENA_ID:'' + r._id + ''" style="margin-right:4px;padding:4px 8px;background:#d32f2f;color:#fff;border-radius:4px;text-decoration:none;font-size:12px">Moderar</a>'';',
